def get_all_email_words(email_data):
    words = set()
    for email in email_data:
        if email.get("subject"):
            words.update(email["subject"].split())
        if email.get("from_email"):
            words.add(email["from_email"])
        if email.get("body"):
            words.update(email["body"].split())
    return list(words)

